Add configuration fields for degradation policy and related settings.

## Implementation Details

### Config Additions

```rust
#[derive(Debug, Clone, Copy, Serialize, Deserialize, Default, PartialEq)]
#[serde(rename_all = "snake_case")]
pub enum DegradationPolicy {
    /// Reject all connections when no healthy proxy (most secure)
    #[default]
    FailClosed,
    /// Try each proxy in order until one works
    TryAll,
    /// Use the most recently healthy proxy
    UseLast,
    /// Connect directly without proxy (must enable allow_direct_fallback)
    Direct,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Settings {
    // ... existing fields

    /// Policy when all proxies are unhealthy
    #[serde(default)]
    pub degradation_policy: DegradationPolicy,

    /// Seconds to wait before applying degradation (debounce)
    #[serde(default = "default_degradation_delay")]
    pub degradation_delay_secs: u64,

    /// Allow direct connections as fallback (required for Direct policy)
    #[serde(default)]
    pub allow_direct_fallback: bool,
}

fn default_degradation_delay() -> u64 {
    5
}
```

### Validation

```rust
impl AppConfig {
    pub fn validate(&self) -> Result<()> {
        // ... existing validation

        // Direct policy requires explicit opt-in
        if self.settings.degradation_policy == DegradationPolicy::Direct
            && !self.settings.allow_direct_fallback
        {
            anyhow::bail!(
                "degradation_policy 'direct' requires allow_direct_fallback = true"
            );
        }

        Ok(())
    }
}
```

### Example Config

```toml
[settings]
# Default: fail_closed (safest)
degradation_policy = "fail_closed"

# Wait 5 seconds before applying degradation
