fn service_install(service_file: PathBuf) -> Result<()> {
    // Verify we have the service file
    if !service_file.exists() {
        anyhow::bail!(
            "Service file not found: {}\nRun 'rp service generate' first",
            service_file.display()
        );
    }

    // Check if we're running as root
    if !running_as_root() {
        anyhow::bail!(
            "Installation requires root privileges.\n\
             Run with sudo: sudo rp service install"
        );
    }

    let dest = Path::new("/etc/systemd/system/rp.service");

    // Optionally validate with systemd-analyze
    if let Ok(output) = Command::new("systemd-analyze")
        .args(["verify", service_file.to_str().unwrap()])
        .output()
    {
        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            anyhow::bail!("Service file validation failed:\n{}", stderr);
        }
    }

    // Copy service file
    std::fs::copy(&service_file, dest)?;
    println!("Installed service file to {}", dest.display());

    // Reload systemd
    let status = Command::new("systemctl")
        .arg("daemon-reload")
        .status()?;

    if !status.success() {
        anyhow::bail!("Failed to reload systemd daemon");
    }
    println!("Reloaded systemd daemon");

    println!();
    println!("Service installed! To enable and start:");
    println!("  sudo systemctl enable --now rp");

    Ok(())
}

fn running_as_root() -> bool {
    #[cfg(unix)]
    { unsafe { libc::geteuid() } == 0 }

    #[cfg(not(unix))]
    { false }
}
```

